parameters.jsonBody:
{
  "contents": [{
    "parts":[{"text": "You are an expert LinkedIn growth hacker and software engineer. Write a highly engaging, concise post (under 150 words) about a recent AI or coding trend. It must be professional and insightful with max 3 hashtags.\n\nCRITICAL INSTRUCTION: At the very end of your response, on a new line, write a 3-6 word visual description of a conceptual image to accompany the post. Wrap it exactly in brackets like this: [IMAGE: futuristic robot typing code]. Do not miss this step."}]
  }]
}

parameters.jsCode:
const responseText = $input.first().json.candidates[0].content.parts[0].text;

// Extract the image prompt inside [IMAGE: ...]
const imageRegex = /\[IMAGE:\s*(.*?)\]/i;
const imageMatch = responseText.match(imageRegex);

let imagePrompt = "futuristic artificial intelligence coding screen with bright neon colors concept art";
let postText = responseText;

if (imageMatch && imageMatch[1]) {
  imagePrompt = imageMatch[1].trim() + " bright colorful highly detailed digital art 4k trending";
  // Remove the tag from the final string we will post to LinkedIn
  postText = responseText.replace(imageRegex, '').trim();
}

// Generate the Pollinations URL for the image
const encodedPrompt = encodeURIComponent(imagePrompt);
// Pollinations is a free keyless image generator
const imageUrl = `https://pollinations.ai/p/${encodedPrompt}?width=1080&height=1080&nologo=true&enhance=true`;

return {
  postText: postText,
  imageUrl: imageUrl
};

const postText = $input.first().json.postText;
const imageUrl = $input.first().json.imageUrl;

// In older n8n versions, $resumeWebhookUrl might need to be constructed
// Usually n8n populates it if there's a Webhook waiting. 
// To be safe, we dynamically pull the generated webhook wait url from n8n Context
const webhookUrl = $('Wait For Approval').execution?.resumeUrl || $resumeWebhookUrl || 'URL-Missing';

const subject = "⏳ Action Required: Approve your new LinkedIn Post!";

const emailBody = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 8px">
  <h2>🤖 Your new AI LinkedIn Post is Ready</h2>
  <p>Gemini/OpenAI generated the following update for your LinkedIn network:</p>
  <hr/>
  <div style="background: #f9f9f9; padding: 15px; border-radius: 4px; white-space: pre-wrap;">
    ${postText}
  </div>
  <br>
  <div style="text-align: center">
    <p><strong>Generated Image:</strong></p>
    <img src="${imageUrl}" style="max-width: 100%; border-radius: 8px;" />
  </div>
  <hr/>
  <div style="text-align: center; margin-top: 30px">
    <a href="${webhookUrl}" style="background: #0077b5; color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; font-weight: bold; font-size: 16px;">✅ APPROVE & POST TO LINKEDIN</a>
  </div>
  <p style="text-align: center; color: #888; font-size: 12px; margin-top: 20px">If you ignore this email, nothing will be posted.</p>
</div>
`;

return {
  subject: subject,
  html: emailBody,
  postText: postText,
  imageUrl: imageUrl
};
